from instructor import from_openai
from instructor.retry import backoff
from pydantic import BaseModel

class ContentPiece(BaseModel):
    headline: str
    body: str
    tone_score: float = Field(ge=0.8)

@backoff(3)
def generate_content(topic: str) -> ContentPiece:
    client = from_openai(openai_client)
    return client.chat.completions.create(
        model="gpt-4o",
        response_model=ContentPiece,
        messages=[
            {"role": "system", "content": "Maintain brand voice: professional, insightful"},
            {"role": "user", "content": f"Generate content about {topic}"}
        ],
        temperature=0.1
    )

result = generate_content("AI ethics")

import { fromOpenai } from '@instructor-ai/instructor';
import { z } from 'zod';

const ContentSchema = z.object({
  title: z.string().max(60),
  tone: z.enum(['professional', 'friendly', 'authoritative']),
  sections: z.array(z.string()).min(3),
  keywords: z.array(z.string()).min(3)
});

type Content = z.infer<typeof ContentSchema>;

const client = fromOpenai(openai);

const content = await client.chat.completions.create({
  model: 'gpt-4o',
  response_model: ContentSchema,
  messages: [{ role: 'user', content: 'Write about sustainable tech' }]
}) as Content;

