from vex import verify
from instructor import from_openai

client = from_openai(openai_client)

@verify(guards=[
    "brand_voice_similarity>0.85",
    "sentiment:professional"
])
def generate_brand_content(topic: str) -> BlogPost:
    return client.chat.completions.create(
        model="gpt-4o",
        response_model=BlogPost,
        messages=[{"role": "user", "content": topic}]
    )

post = generate_brand_content("AI content generation")

import { verify } from 'vex-sdk';
import { fromOpenai } from '@instructor-ai/instructor';

const vexClient = fromOpenai(openai);

const generateSecureContent = verify(
  async (topic: string) => {
    const content = await vexClient.chat.completions.create({
      model: 'gpt-4o',
      response_model: ContentSchema,
      messages: [{ role: 'user', content: topic }]
    }) as Content;

    return content;
  },
  {
    guards: [
      'brand_consistency>0.9',
      'seo_compliance',
      'originality_score>0.8'
    ]
  }
);

const post = await generateSecureContent('AI ethics');
